  int izq;        // desplazamiento del subarbol izquierdo (-1 si no hay)
  int der;        // desplazamiento del subarbol derecho   (-1 si no hay)
  short tam_llave; // tamano en bytes de la llave
  short tam_valor; // tamano en bytes del valor
} NodoArch;

// Busca la llave en el abb almacenado en el archivo dicc partiendo del
// nodo raiz ubicado en el desplazamiento pos.  Si la encuentra, escribe
// su valor en la salida estandar (seguido de \n) y retorna 1.  Si la
// llave no existe, retorna 0.
int buscar(FILE *dicc, char *nom, int pos, const char *llave_buscar) {
  while (pos != -1) {
    if (fseek(dicc, (long)pos, SEEK_SET) != 0) {
      perror(nom);
      exit(1);
    }
    NodoArch nodoa;
    if (fread(&nodoa, sizeof(NodoArch), 1, dicc) != 1) {
      perror(nom);
      exit(1);
    }
    char *llave = malloc(nodoa.tam_llave + 1);
    if (fread(llave, nodoa.tam_llave, 1, dicc) != 1) {
      free(llave);
      perror(nom);
      exit(1);
    }
    llave[nodoa.tam_llave] = '\0';

    int cmp = strcmp(llave_buscar, llave);
    if (cmp == 0) {
      // Encontrada: leer valor y entregarlo
      char *valor = malloc(nodoa.tam_valor + 1);
      if (fread(valor, nodoa.tam_valor, 1, dicc) != 1) {
        free(llave);
        free(valor);
        perror(nom);
        exit(1);
      }
      valor[nodoa.tam_valor] = '\0';
      fwrite(valor, 1, nodoa.tam_valor, stdout);
      fputc('\n', stdout);
      free(llave);
      free(valor);
      return 1;
    }

    free(llave);

    if (cmp < 0)
      pos = nodoa.izq;
    else
      pos = nodoa.der;
  }
  return 0;
}

int main(int argc, char **argv) {
  if (argc != 3) {
    fprintf(stderr, "uso: ./consultar.bin <archivo> <llave>\n");
    exit(1);
  }
  char *nom = argv[1];
  char *llave = argv[2];

  FILE *dicc = fopen(nom, "r");
  if (dicc == NULL) {
    perror(nom);
    exit(1);
  }

  // Buscar la llave partiendo de la raiz en el desplazamiento 0
  if (!buscar(dicc, nom, 0, llave)) {
    fprintf(stderr, "La llave %s no existe\n", llave);
    fclose(dicc);
    exit(1);
  }

  fclose(dicc);
  return 0;
}
